修改数据结构，将 `A.matrixValues[i]` 和 `A.mtxIndL[i]` 替换为一维数组 `A.flat_values` 和 `A.flat_cols`，并使用行偏移数组 `A.row_ptr`。循环改为：
for (local_int_t i=0; i< nrow; i++) {
  double sum = 0.0;
  const local_int_t start = A.row_ptr[i];
  const local_int_t end = A.row_ptr[i+1];
  for (local_int_t j=start; j<end; j++) {
    sum += A.flat_values[j] * xv[A.flat_cols[j]];
  }
  yv[i] = sum;
}

#pragma omp parallel for
for (local_int_t i=0; i< nrow; i++) {
  double sum = 0.0;
  const double* cv = A.matrixValues[i];
  const local_int_t* ci = A.mtxIndL[i];
  int nnz = A.nonzerosInRow[i];
  int j = 0;
  // 展开 4 路
  for (; j <= nnz - 4; j += 4) {
    sum += cv[j] * xv[ci[j]] + cv[j+1] * xv[ci[j+1]] + cv[j+2] * xv[ci[j+2]] + cv[j+3] * xv[ci[j+3]];
  }
  for (; j < nnz; j++) {
    sum += cv[j] * xv[ci[j]];
  }
  yv[i] = sum;
}

在循环外提取对角线元素，或在存储时将对角线元素与非对角线元素分离。在内层循环中，避免将对角线元素乘入 sum 再在循环外减去的冗余操作。通过调整数据结构，使内层循环仅遍历非对角线元素：
```cpp
// 优化后内层循环示例
for (int j = 0; j < currentNumberOfNonzeros; j++) {
  local_int_t curCol = currentColIndices[j];
  if (curCol != i) {
    sum -= currentValues[j] * xv[curCol];
  }
}
xv[i] = sum / currentDiagonal;
```
更彻底的改动是在预处理阶段将对角线元素单独存储在连续数组 `invDiagonal[i] = 1.0 / matrixDiagonal[i][0]` 中，消除除法并减少指针间接引用。

原始代码中 `A.matrixValues[i]` 和 `A.mtxIndL[i]` 是二维指针数组，导致每次外层循环都要进行两次指针跳转。应将其扁平化为标准的一维 CSR (Compressed Sparse Row) 格式：
```cpp
// 使用一维连续数组
const double * const values = A.flatMatrixValues; // 一维数组
const local_int_t * const colIndices = A.flatMtxIndL;
const local_int_t * const rowOffsets = A.rowOffsets;
// 循环内部：
local_int_t rowStart = rowOffsets[i];
local_int_t rowEnd = rowOffsets[i+1];
for (local_int_t j = rowStart; j < rowEnd; j++) {
  // 连续内存访问...
}
```

由于行与行之间存在数据依赖，无法直接使用 `#pragma omp parallel for`。必须在预处理阶段对矩阵的邻接图进行染色（Coloring），使得相同颜色的行之间没有数据依赖。然后按颜色顺序进行并行计算：
```cpp
for (int color = 0; color < numColors; color++) {
  int colorSize = colorSizes[color];
  const local_int_t* rows = colorPointer[color];
  #pragma omp parallel for schedule(static)
  for (int k = 0; k < colorSize; k++) {
    local_int_t i = rows[k];
    // 执行该行的 GS 迭代...
  }
}
```

void sparse_matvec(int n, const int *rowptr, const int *colidx, const double *values, const double *x, double *y)
{
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; i++) {
        double sum = 0.0;
        int start = rowptr[i];
        int end = rowptr[i + 1];
        int j = start;
        // 4路循环展开以减少分支开销并提升 ILP
        for (; j <= end - 4; j += 4) {
            sum += values[j] * x[colidx[j]]
                 + values[j+1] * x[colidx[j+1]]
                 + values[j+2] * x[colidx[j+2]]
                 + values[j+3] * x[colidx[j+3]];
        }
        for (; j < end; j++) {
            sum += values[j] * x[colidx[j]];
        }
        y[i] = sum;
    }
}

double dot_product(const double *x, const double *y, int n)
{
    double sum = 0.0;
    #pragma omp parallel for reduction(+:sum) schedule(static)
    for (int i = 0; i < n; i++) {
        sum += x[i] * y[i];
    }
    return sum;
}

void jacobi_kernel(int tsteps, int n, double *A, double *B)
{
    int t, i, j;
    for (t = 0; t < tsteps; t++) {
        #pragma omp parallel for default(shared) private(i, j)
        for (i = 1; i < n - 1; i++) {
            #pragma omp simd
            for (j = 1; j < n - 1; j++) {
                B[i * n + j] = 0.2 * (A[i * n + j] + A[i * n + j - 1] + A[i * n + j + 1] + A[(i + 1) * n + j] + A[(i - 1) * n + j]);
            }
        }
        #pragma omp parallel for default(shared) private(i, j)
        for (i = 1; i < n - 1; i++) {
            #pragma omp simd
            for (j = 1; j < n - 1; j++) {
                A[i * n + j] = 0.2 * (B[i * n + j] + B[i * n + j - 1] + B[i * n + j + 1] + B[(i + 1) * n + j] + B[(i - 1) * n + j]);
            }
        }
    }
}

// 将外层循环分解为 Block_i 和 Block_j，以确保工作集拟合在 L2/L3 缓存中
#define BLOCK_I 64
#define BLOCK_J 64
// 在多线程基础上，对 i 和 j 维度进行分块处理，限制活跃数据集大小，减少 Cache Line 冲突失效。

将 `C[i][j] *= beta` 与乘加计算融合，并对 `i, j, k` 三层循环进行分块（Tiling），以最大化 L1/L2 缓存复用。同时使用 SIMD 向量化（如 AVX2/AVX-512）和 OpenMP 多线程并行化。

优化后的核心代码结构如下：
```cpp
#pragma omp parallel for collapse(2)
for (int si = 0; si < _PB_NI; si += BLOCK_I) {
  for (int sj = 0; sj < _PB_NJ; sj += BLOCK_J) {
    // 融合初始化：仅在分块首次访问时乘以 beta
    for (int i = si; i < MIN(si + BLOCK_I, _PB_NI); i++) {
      for (int j = sj; j < MIN(sj + BLOCK_J, _PB_NJ); j++) {
        C[i][j] *= beta;
      }
    }
    for (int sk = 0; sk < _PB_NK; sk += BLOCK_K) {
      for (int i = si; i < MIN(si + BLOCK_I, _PB_NI); i++) {
        for (int k = sk; k < MIN(sk + BLOCK_K, _PB_NK); k++) {
          DATA_TYPE alpha_A = alpha * A[i][k];
          #pragma omp simd
          for (int j = sj; j < MIN(sj + BLOCK_J, _PB_NJ); j++) {
            C[i][j] += alpha_A * B[k][j];
          }
        }
      }
    }
  }
}
```

将两个三层循环的顺序从 i-j-k 改为 i-k-j。这样最内层循环 `j` 的内存访问是完全连续的（Row-major），可以完美利用 CPU 的 L1 Cache 空间局部性并自动触发硬件预取，同时允许编译器进行 SIMD 向量化。

修改后的代码：
// 第一个矩阵乘法
for (i = 0; i < _PB_NI; i++) {
  for (j = 0; j < _PB_NJ; j++) {
    tmp[i][j] = SCALAR_VAL(0.0);
  }
  for (k = 0; k < _PB_NK; k++) {
    DATA_TYPE alpha_A = alpha * A[i][k];
    for (j = 0; j < _PB_NJ; j++) {
      tmp[i][j] += alpha_A * B[k][j];
    }
  }
}
// 第二个矩阵乘法
for (i = 0; i < _PB_NI; i++) {
  for (j = 0; j < _PB_NL; j++) {
    D[i][j] *= beta;
  }
  for (k = 0; k < _PB_NJ; k++) {
    DATA_TYPE tmp_val = tmp[i][k];
    for (j = 0; j < _PB_NL; j++) {
      D[i][j] += tmp_val * C[k][j];
    }
  }
}

在循环重排的基础上，引入 2D/3D 循环分块（Tiling/Blocking）以适配 L2/L3 缓存大小，并使用 `#pragma omp parallel for` 进行多核并行化。

示例代码片段：
#pragma omp parallel for collapse(2) private(k, j)
for (int i = 0; i < _PB_NI; i += BLOCK_I) {
  for (int k = 0; k < _PB_NK; k += BLOCK_K) {
    for (int j = 0; j < _PB_NJ; j += BLOCK_J) {
      // 内层微内核进行分块计算...
    }
  }
}

将传统的 i-j-k 循环重排为 i-k-j 循环，以确保最内层对所有矩阵的访问都是行连续的（空间局部性）。同时，引入 OpenMP 开启多线程并行化，并使用 `#pragma omp simd` 引导编译器进行 AVX2/AVX-512 向量化。对于大矩阵，应用 Block Size = 64 或 128 的分块技术。

示例代码改动 (以 E := A*B 为例):
```cpp
#pragma omp parallel for collapse(2) private(i, k, j)
for (int i = 0; i < _PB_NI; i++) {
  for (int j = 0; j < _PB_NJ; j++) {
    E[i][j] = SCALAR_VAL(0.0);
  }
  for (int k = 0; k < _PB_NK; k++) {
    #pragma omp simd
    for (int j = 0; j < _PB_NJ; j++) {
      E[i][j] += A[i][k] * B[k][j];
    }
  }
}
```

void kernel_syrk(int n, int m, DATA_TYPE alpha, DATA_TYPE beta, DATA_TYPE POLYBENCH_2D(C,N,N,n,n), DATA_TYPE POLYBENCH_2D(A,N,M,n,m)) {
  int i, j, k;
  // 1. 先统一对 C 进行 beta 缩放，保证连续内存写入
  for (i = 0; i < _PB_N; i++) {
    for (j = 0; j <= i; j++) {
      C[i][j] *= beta;
    }
  }
  // 2. 交换循环顺序，将 k 移到外层，i 和 j 在内层，并进行分块(Tiling)或向量化
  // 这样 A[i][k] 在内层循环中是循环不变的，A[j][k] 的访问可以通过转置或局部累加优化
  for (i = 0; i < _PB_N; i++) {
    for (k = 0; k < _PB_M; k++) {
      DATA_TYPE temp = alpha * A[i][k];
      #pragma omp simd
      for (j = 0; j <= i; j++) {
        C[i][j] += temp * A[j][k];
      }
    }
  }
}

#pragma omp parallel for private(j, k) schedule(static)
for (i = 0; i < _PB_N; i++) {
  for (j = 0; j <= i; j++) {
    C[i][j] *= beta;
  }
  for (k = 0; k < _PB_M; k++) {
    DATA_TYPE temp = alpha * A[i][k];
    #pragma omp simd
    for (j = 0; j <= i; j++) {
      C[i][j] += temp * A[j][k];
    }
  }
}

void kernel_syr2k(int n, int m, DATA_TYPE alpha, DATA_TYPE beta, DATA_TYPE POLYBENCH_2D(C,N,N,n,n), DATA_TYPE POLYBENCH_2D(A,N,M,n,m), DATA_TYPE POLYBENCH_2D(B,N,M,n,m)) {
  int i, j, k;
  // 1. 独立初始化 C 的下三角部分，利用 OpenMP 并行化
  #pragma omp parallel for private(j)
  for (i = 0; i < _PB_N; i++) {
    for (j = 0; j <= i; j++) {
      C[i][j] *= beta;
    }
  }
  // 2. 交换 k 和 j 循环，使最内层对 C, A, B 的访问在内存中连续（行优先）
  // 3. 引入 OpenMP 并在外层进行分块（Tiling）以最大化 L1/L2 缓存命中率
  #pragma omp parallel for private(k, j)
  for (i = 0; i < _PB_N; i++) {
    for (k = 0; k < _PB_M; k++) {
      DATA_TYPE alpha_A_ik = alpha * A[i][k];
      DATA_TYPE alpha_B_ik = alpha * B[i][k];
      // 向量化友好的最内层循环
      #pragma omp simd
      for (j = 0; j <= i; j++) {
        C[i][j] += A[j][k] * alpha_B_ik + B[j][k] * alpha_A_ik;
      }
    }
  }
}

将更新 ey、ex 和 hz 的多个独立 i, j 嵌套循环融合为一个统一的 i, j 循环（在处理边界条件的前提下），以提高空间局部性，并使用 #pragma omp parallel for simd 引导编译器进行多线程并行化和 SIMD 向量化。修改后的核心结构如下：

for (t = 0; t < _PB_TMAX; t++) {
  // 1. 边界条件更新
  for (j = 0; j < _PB_NY; j++) ey[0][j] = _fict_[t];

  // 2. 融合 ey 和 ex 的更新
  #pragma omp parallel for collapse(2)
  for (i = 1; i < _PB_NX; i++) {
    for (j = 1; j < _PB_NY; j++) {
      ey[i][j] = ey[i][j] - 0.5f * (hz[i][j] - hz[i-1][j]);
      ex[i][j] = ex[i][j] - 0.5f * (hz[i][j] - hz[i][j-1]);
    }
  }
  // 处理 i=0 的 ex 边界和 j=0 的 ey 边界...

  // 3. 更新 hz
  #pragma omp parallel for collapse(2)
  for (i = 0; i < _PB_NX - 1; i++) {
    for (j = 0; j < _PB_NY - 1; j++) {
      hz[i][j] = hz[i][j] - 0.7f * (ex[i][j+1] - ex[i][j] + ey[i+1][j] - ey[i][j]);
    }
  }
}

将 3D 空间循环（i, j, k）划分为较小的 3D 块（Block Size: Ti, Tj, Tk），使每个块的数据能够完全容纳在 L1/L2 缓存中。代码改动示例：
